// MIPS32r2 little-endian userspace interpreter for doomgeneric_mips.
// Executes the ELF, servicing the Linux-style syscalls the binary emits
// (numbers are x86-64 style, args in $a0-$a3,$t0,$t1, number in $v0, ret in $v0).

const fs = require('fs');
