for (let i = 0; i < phnum; i++) {
  const off = phoff + i * phentsize;
  const p_type = elf.readUInt32LE(off);
  if (p_type !== 1) continue; // PT_LOAD
  const p_offset = elf.readUInt32LE(off + 4);
  const p_vaddr = elf.readUInt32LE(off + 8);
  const p_filesz = elf.readUInt32LE(off + 16);
  const p_memsz = elf.readUInt32LE(off + 20);
  segments.push({ p_offset, p_vaddr, p_filesz, p_memsz });
  const end = p_vaddr + p_memsz;
  if (end > memTop) memTop = end;
}

